import{_ as e,o as d,c as l,a3 as a}from"./chunks/framework.d0TBG0Rg.js";const u=JSON.parse('{"title":"中二节奏专项","description":"中二节奏查分、查歌、B30 等功能的用法说明。","frontmatter":{"title":"中二节奏专项","description":"中二节奏查分、查歌、B30 等功能的用法说明。"},"headers":[],"relativePath":"features/chunithm.md","filePath":"features/chunithm.md"}'),c={name:"features/chunithm.md"};function o(i,t,r,s,n,h){return d(),l("div",null,[...t[0]||(t[0]=[a('<h1 id="🎹-中二节奏-chunithm" tabindex="-1">🎹 中二节奏 (Chunithm) <a class="header-anchor" href="#🎹-中二节奏-chunithm" aria-label="Permalink to &quot;🎹 中二节奏 (Chunithm)&quot;">​</a></h1><blockquote><p>中二节奏（Chunithm）的查分和查歌功能，目前只支持国服。</p></blockquote><br><div class="info custom-block"><p class="custom-block-title">💡 数据来源说明</p><p>目前中二节奏模块 <strong>仅支持国服</strong>，所有数据均完全来源于 <a href="https://www.diving-fish.com/" target="_blank" rel="noreferrer">水鱼查分器 (diving-fish)</a>。</p></div><div class="mzk-card mzk-card--yellow"><h3>🏆 个人成绩与 Rating</h3><p>用于查询您在国服的当前个人实力数据。</p><div class="mzk-table-wrapper"><table tabindex="0"><thead><tr><th style="text-align:left;">指令</th><th style="text-align:left;">说明</th><th style="text-align:left;">示例</th></tr></thead><tbody><tr><td style="text-align:left;"><code>chu b30</code></td><td style="text-align:left;">查询个人 B30、R10 成绩记录以及总 Rating</td><td style="text-align:left;"><code>chu b30</code></td></tr></tbody></table></div></div><div class="mzk-card mzk-card--red"><h3>🎶 歌曲与谱面信息</h3><div class="mzk-alert">⚠️ <strong>注意：</strong> <code>chuinfo</code> 和 <code>chuchart</code> <strong>必须使用歌曲 ID</strong> 进行查询。</div><div class="mzk-table-wrapper"><table tabindex="0"><thead><tr><th style="text-align:left;">指令</th><th style="text-align:left;">说明</th><th style="text-align:left;">示例</th></tr></thead><tbody><tr><td style="text-align:left;"><code>chu [曲名]</code></td><td style="text-align:left;">查询歌曲 ID (不区分大小写，仅匹配歌曲名称)</td><td style="text-align:left;"><code>chu 祈愿</code></td></tr><tr><td style="text-align:left;"><code>chuinfo [ID]</code></td><td style="text-align:left;">查询歌曲基本信息 (仅支持 ID 查询)</td><td style="text-align:left;"><code>chuinfo 1145</code></td></tr><tr><td style="text-align:left;"><code>chuchart [ID]</code></td><td style="text-align:left;">查询歌曲谱面 (仅支持 ID 查询)。默认返回 master 难度</td><td style="text-align:left;"><code>chuchart 1145</code></td></tr><tr><td style="text-align:left;"><code>chuchart [ID][难度]</code></td><td style="text-align:left;">添加 <code>ex</code>, <code>ma</code>, <code>ult</code> 后缀查看 Expert/Master/Ultima 难度</td><td style="text-align:left;"><code>chuchart 1145ult</code></td></tr></tbody></table></div></div>',6)])])}const g=e(c,[["render",o]]);export{u as __pageData,g as default};
